#include <iostream>
#include <vector>
using namespace std;

// === 1. БАЗОВИЙ КЛАС (2 параметри + Поліморфізм) ===
class BaseModel {
protected:
    int* data;
    int size;   // Параметр 1
    int id;     // Параметр 2

public:
    BaseModel(int s, int newId) {
        size = s;
        id = newId;
        data = new int[size];
        for(int i = 0; i < size; i++) data[i] = 1;
    }

    BaseModel(const BaseModel& other) {
        size = other.size;
        id = other.id;
        data = new int[size];
        for(int i = 0; i < size; i++) data[i] = other.data[i];
    }

    // Віртуальний деструктор - обов'язковий при поліморфізмі!
    virtual ~BaseModel() {
        delete[] data;
    }

    // Чисто віртуальна функція -> робить клас абстрактним
    virtual void runDiagnostics() const = 0;
};

// === 2. ПОХІДНИЙ КЛАС (Додає ще 2 параметри) ===
class AdvancedModel : public BaseModel {
private:
    bool isActive;  // Параметр 3
    int level;      // Параметр 4

public:
    AdvancedModel(int s, int newId, bool act, int lvl) : BaseModel(s, newId) {
        isActive = act;
        level = lvl;
    }

    AdvancedModel(const AdvancedModel& other) : BaseModel(other) {
        isActive = other.isActive;
        level = other.level;
    }

    // Перевизначення віртуальної функції
    void runDiagnostics() const override {
        cout << "[Діагностика] Модель ID: " << id << " | Рівень: " << level
             << " | Статус: " << (isActive ? "OK" : "ОФЛАЙН") << endl;
    }

    // Перевантаження == (перевіряємо ВСІ 4 поля + масив)
    bool operator==(const AdvancedModel& other) const {
        if (size != other.size || id != other.id ||
            isActive != other.isActive || level != other.level) {
            return false;
        }
        for(int i = 0; i < size; i++) {
            if (data[i] != other.data[i]) return false;
        }
        return true;
    }

    // Перевантаження +
    AdvancedModel operator+(const AdvancedModel& other) const {
        AdvancedModel result(size, id, isActive, level);
        for(int i = 0; i < size; i++) {
            result.data[i] = data[i] + other.data[i];
        }
        return result;
    }

    // Перевантаження <<
    friend ostream& operator<<(ostream& os, const AdvancedModel& obj) {
        os << "ID: " << obj.id << ", Рівень: " << obj.level << "\n";
        os << "Статус: " << (obj.isActive ? "Активний" : "Вимкнений") << "\n";
        os << "Дані: [ ";
        for(int i = 0; i < obj.size; i++) os << obj.data[i] << " ";
        os << "]\n";
        return os;
    }
};

// === 3. MAIN ===
int main() {
    cout << "--- ЧАСТИНА 1: ОПЕРАТОРИ ---\n";
    AdvancedModel m1(3, 10, true, 5);
    AdvancedModel m2(3, 10, true, 5);

    AdvancedModel m3 = m1 + m2;
    cout << m3;

    if (m1 == m2) cout << "Об'єкти m1 та m2 рівні!\n\n";

    cout << "--- ЧАСТИНА 2: STL ТА ПОЛІМОРФІЗМ ---\n";
    // Вектор вказівників на БАЗОВИЙ клас
    vector<BaseModel*> cluster;

    cluster.push_back(new AdvancedModel(2, 101, true, 10));
    cluster.push_back(new AdvancedModel(4, 202, false, 99));
    cluster.push_back(new AdvancedModel(m3)); // Копія об'єкта з operator+

    // Поліморфний виклик для всіх об'єктів у векторі
    for (BaseModel* model : cluster) {
        model->runDiagnostics();
    }

    // Очищення пам'яті (викличе віртуальний деструктор)
    for (BaseModel* model : cluster) {
        delete model;
    }

    return 0;
}
